-- Seed: Assessment-Dimensions-Empfehlungen (UX-Review Sprint 37)
-- 24 Texte (18 schwach = 6 Dimensionen × 3 Archetypen + 6 gut), je DE + EN = 48 Zeilen.
-- Werden in der Executive Summary (/zusammenfassung) als Reifegrad-Empfehlung je
-- Dimension angezeigt und sind über den Content-Library-Editor im Admin-Bereich
-- editierbar. Die messages/*.json-Werte bleiben als Fallback bestehen.
-- Idempotent: löscht vorab evtl. bestehende summary.dim.*-Zeilen (kein UNIQUE-Constraint).

DELETE FROM public.content_library WHERE context_key LIKE 'summary.dim.%';

